package m1.pkg1;

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
            Scanner sc = new Scanner(System.in);
                    AdminService adminService = new AdminService();
                            ExhibitService exhibitService = new ExhibitService();
                                    MonitorVisitor visitorService = new MonitorVisitor();

                                            while (true) {
                                                        System.out.println("\n============================================");
                                                                    System.out.println("      WELCOME TO THE NATIONAL MUSEUM        ");
                                                                                System.out.println("============================================");
                                                                                            System.out.println("[1] VISITOR MODE (Registration & Exhibits)");
                                                                                                        System.out.println("[2] ADMINISTRATOR MODE (Staff Login)");
                                                                                                                    System.out.println("[0] Exit Program");
                                                                                                                                System.out.print("Select Mode > ");
                                                                                                                                            
                                                                                                                                                        int mode = sc.nextInt();

                                                                                                                                                                    if (mode == 1) {
                                                                                                                                                                                    
                                                                                                                                                                                                    String visitorName = visitorService.registerVisitorEntry();
                                                                                                                                                                                                                    
                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                    if (visitorName != null) {
                                                                                                                                                                                                                                                                        visitorPortal(exhibitService, adminService, visitorName);
                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                    } else if (mode == 2) {
                                                                                                                                                                                                                                                                                                                    if (adminService.login()) {
                                                                                                                                                                                                                                                                                                                                        adminPortal(adminService, visitorService);
                                                                                                                                                                                                                                                                                                                                                        } else {
                                                                                                                                                                                                                                                                                                                                                                            System.out.println(">>> Negative: Invalid Credentials. Access Denied.");
                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                        } else if (mode == 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                        System.out.println("Thank you for visiting the National Museum!");
                                                                                                                                                                                                                                                                                                                                                                                                                                        break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                    } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    System.out.println("Invalid option. Please try again.");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    public static void visitorPortal(ExhibitService ex, AdminService admin, String name) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Scanner sc = new Scanner(System.in);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    while (true) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                System.out.println("\n--- VISITOR MENU (Logged in as: " + name.toUpperCase() + ") ---");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            System.out.println("[1] Search Exhibit Information");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        System.out.println("[2] View Exhibit");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    System.out.println("[3] Back to Main Menu");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                System.out.print("Action > ");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            int choice = sc.nextInt();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (choice == 1) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ex.searchExhibit(); 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    } else if (choice == 2) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    System.out.print("Enter your Booking ID: ");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    int bId = sc.nextInt();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   if (admin.verifyTicket(bId)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       ex.exploreGallery(); 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   } else if (choice == 3) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  public static void adminPortal(AdminService admin, MonitorVisitor visitorService) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      Scanner sc = new Scanner(System.in); // Siguraduhin na may scanner dito
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          while (true) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  System.out.println("\n--- ADMINISTRATOR DASHBOARD ---");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          System.out.println("[1] Add New Admin");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  System.out.println("[2] Update Admin Record");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          System.out.println("[3] Delete Admin Record");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  System.out.println("[4] Monitor & Manage Bookings");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          System.out.println("[5] View All Admin Accounts");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  System.out.println("[6] VIEW VISITOR ENTRY LOGS");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          System.out.println("[7] Logout");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  System.out.print("Action > ");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (!sc.hasNextInt()) { 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              sc.next(); 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          int choice = sc.nextInt();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  sc.nextLine(); 

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          switch (choice) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      case 1: admin.addAdmin(); break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  case 2: admin.updateAdmin(); break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              case 3: admin.deleteAdmin(); break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          case 4: admin.manageBookings(); break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      case 5: admin.showAdminRecords(); break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  case 6: visitorService.displayAllEntries(); break; 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              case 7: 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              System.out.println("Logging out...");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return; 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          default: 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          System.out.println("Invalid choice. Try again.");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }